   236→class GrpcMuxDelta : public GrpcMuxImpl<DeltaSubscriptionState, DeltaSubscriptionStateFactory,
   237→                                        envoy::service::discovery::v3::DeltaDiscoveryRequest,
   238→                                        envoy::service::discovery::v3::DeltaDiscoveryResponse> {
   239→public:
   240→  GrpcMuxDelta(GrpcMuxContext& grpc_mux_context, bool skip_subsequent_node);
